<?php $title='Playlists';require __DIR__.'/partials/header.php';?><div class="row g-4"><div class="col-lg-4"><div class="card"><div class="card-body"><h1 class="h4">New playlist</h1><form method="post" action="/playlists"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input class="form-control mb-2" name="name" placeholder="Name" required><textarea class="form-control mb-3" name="description" placeholder="Description"></textarea><button class="btn btn-primary">Create</button></form></div></div></div><div class="col-lg-8"><h1 class="h4">Playlists</h1><?php foreach($playlists as $p):?><div class="card mb-2"><div class="card-body d-flex justify-content-between align-items-center"><span><strong><?=e($p['name'])?></strong><small class="text-secondary"> · <?=e((string)$p['video_count'])?> videos</small></span><form method="post" action="/playlists/videos" class="d-flex gap-2"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="playlist_id" value="<?=e((string)$p['id'])?>"><select class="form-select form-select-sm" name="video_id" required><option value="">Add video</option><?php foreach($videos as $v):?><option value="<?=e((string)$v['id'])?>"><?=e($v['title'])?></option><?php endforeach?></select><button class="btn btn-sm btn-outline-primary">Add</button></form></div></div><?php endforeach?></div></div><?php require __DIR__.'/partials/footer.php'; ?>
